   371→  }
   372→
   373→  /**
   374→   * Handles connection close.
   375→   *
   376→   * @param {ServerConnection} connection - The closed connection
   377→   * @private
   378→   */
   379→  _handleConnectionClose(connection) {
   380→    this._connections.delete(connection.id);
   381→    this.emit('disconnection', connection);
   382→  }
   383→
   384→  /**
   385→   * Handles server-level errors.
   386→   *
   387→   * @param {Error} error - The error that occurred
   388→   * @private
   389→   */
   390→  _handleServerError(error) {
   391→    this.emit('error', error);
   392→  }
   393→
   394→  /**
   395→   * Gracefully shuts down the server.
   396→   *
   397→   * Stops accepting new connections, drains existing connections,
   398→   * and closes the server.
   399→   *
   400→   * @param {Object} [options] - Shutdown options
   401→   * @param {number} [options.drainTimeout=30000] - Maximum time to wait for connections to drain
   402→   * @returns {Promise<void>}
   403→   */
   404→  async shutdown(options = {}) {
   405→    const drainTimeout = options.drainTimeout ?? 30000;
   406→
   407→    if (this.state === ServerState.STOPPED) {
   408→      return;
   409→    }
   410→
   411→    this.state = ServerState.DRAINING;
   412→
   413→    // Stop accepting new connections
   414→    if (this._server) {
   415→      this._server.close();
   416→    }
   417→
   418→    // Drain existing connections
   419→    const drainPromises = [];
   420→    for (const connection of this._connections.values()) {
   421→      drainPromises.push(connection.drain(drainTimeout));
   422→    }
   423→
   424→    // Wait for all connections to drain (with timeout)
   425→    await Promise.race([
   426→      Promise.all(drainPromises),
   427→      new Promise((resolve) => setTimeout(resolve, drainTimeout)),
   428→    ]);
   429→
   430→    // Force close any remaining connections
   431→    for (const connection of this._connections.values()) {
   432→      if (connection.state !== ConnectionState.CLOSED) {
   433→        connection.close();
   434→      }
   435→    }
   436→
   437→    this._connections.clear();
   438→    this.state = ServerState.STOPPED;
   439→    this.emit('close');
   440→  }
   441→
   442→  /**
   443→   * Forcefully stops the server.
   444→   *
   445→   * Immediately closes all connections and the server.
   446→   *
   447→   * @returns {Promise<void>}
   448→   */
   449→  async stop() {
   450→    if (this.state === ServerState.STOPPED) {
   451→      return;
   452→    }
   453→
   454→    // Close all connections immediately
   455→    for (const connection of this._connections.values()) {
   456→      connection.close();
   457→    }
   458→    this._connections.clear();
   459→
   460→    // Close server
   461→    if (this._server) {
   462→      return new Promise((resolve) => {
   463→        // Set up close callback
   464→        const onClose = () => {
   465→          this.state = ServerState.STOPPED;
   466→          this.emit('close');
   467→          resolve();
   468→        };
   469→
   470→        this._server.close(onClose);
   471→
   472→        // Deno workaround: server.close() callback may not fire
   473→        // Use unref to allow event loop to exit, then resolve after short delay
   474→        this._server.unref();
   475→        setTimeout(() => {
   476→          if (this.state !== ServerState.STOPPED) {
   477→            onClose();
   478→          }
   479→        }, 100);
   480→      });
   481→    }
   482→
   483→    this.state = ServerState.STOPPED;
   484→  }
   485→
   486→  /**
   487→   * Returns server statistics.
   488→   *
   489→   * @returns {Object} Server statistics
   490→   */
   491→  getStats() {
   492→    const routerStats = this._router ? this._router.getStats() : null;
   493→
   494→    return {
   495→      state: this.state,
   496→      address: this.address,
   497→      startedAt: this.startedAt,
   498→      uptime: this.startedAt ? Date.now() - this.startedAt : 0,
   499→      connections: {
   500→        current: this._connections.size,
   501→        max: this._config.maxConnections,
   502→        total: this.totalConnections,
   503→      },
   504→      router: routerStats,
   505→      queues: this._queueManager ? this._queueManager.getQueueCount() : 0,
   506→    };
   507→  }
   508→
   509→  /**
   510→   * Gets a specific connection by ID.
   511→   *
   512→   * @param {string} connectionId - Connection ID
   513→   * @returns {ServerConnection|null} The connection or null
   514→   */
   515→  getConnection(connectionId) {
   516→    return this._connections.get(connectionId) || null;
   517→  }
   518→
   519→  /**
   520→   * Gets all active connections.
   521→   *
   522→   * @returns {ServerConnection[]} Array of active connections
   523→   */
   524→  getConnections() {
   525→    return Array.from(this._connections.values());
   526→  }
   527→
   528→  /**
   529→   * Broadcasts a message to all connected clients.
   530→   *
   531→   * @param {import('../protocol/messages.js').Message} message - Message to broadcast
   532→   * @returns {number} Number of clients the message was sent to
   533→   */
   534→  broadcast(message) {
   535→    let count = 0;
   536→    for (const connection of this._connections.values()) {
   537→      if (connection.state === ConnectionState.CONNECTED) {
   538→        connection.send(message);
   539→        count++;
   540→      }
   541→    }
   542→    return count;
   543→  }
   544→
   545→  /**
   546→   * Creates a health check response message.
   547→   *
   548→   * @returns {import('../protocol/messages.js').Message} Health check response
   549→   */
   550→  healthCheck() {
   551→    const stats = this.getStats();
   552→    return createOkResponse({
   553→      healthy: this.state === ServerState.RUNNING,
   554→      state: this.state,
   555→      uptime: stats.uptime,
   556→      connections: stats.connections.current,
   557→      queues: stats.queues,
   558→    });
   559→  }
   560→}
