     1→/**
     2→ * Queue manager implementations for links-queue.
     3→ *
     4→ * This module provides two queue manager implementations:
     5→ *
     6→ * 1. MemoryQueueManager - Lightweight manager for MemoryQueueWithStorage
     7→ *    - No external dependencies
     8→ *    - Uses poll-based visibility timeout handling
     9→ *    - Good for simple use cases and testing
    10→ *
    11→ * 2. LinksQueueManager - Full-featured manager for LinksQueue
    12→ *    - Requires a LinkStore backend for persistence
    13→ *    - Uses timer-based visibility timeout handling
    14→ *    - Supports automatic dead letter queue routing
    15→ *    - Good for production use cases
    16→ *
    17→ * @module queue/manager
    18→ *
    19→ * @see ARCHITECTURE.md - Queue Manager component
    20→ * @see REQUIREMENTS.md - REQ-API-010 through REQ-API-013
    21→ */
    22→
    23→/*
    24→ * Note: The require-await warnings are intentional.
    25→ * This implementation uses async methods for API consistency with other backends
    26→ * (e.g., file-based or network-based managers) even though the in-memory operations
    27→ * are synchronous. This allows for seamless backend swapping.
    28→ */
    29→/* eslint-disable require-await */
    30→
    31→import { QueueError } from './types.js';
    32→import { LinksQueue } from './queue.js';
    33→import { MemoryQueueWithStorage } from './memory-queue.js';
    34→
    35→// =============================================================================
    36→// Queue Entry (Internal - for MemoryQueueManager)
    37→// =============================================================================
    38→
    39→/**
    40→ * Internal entry for a managed queue.
    41→ * @private
    42→ */
    43→class QueueEntry {
    44→  /**
    45→   * @param {MemoryQueueWithStorage} queue - The queue instance
    46→   * @param {import('./types.ts').QueueOptions} options - Options the queue was created with
    47→   */
    48→  constructor(queue, options) {
    49→    /** @type {MemoryQueueWithStorage} The queue instance. */
    50→    this.queue = queue;
    51→
    52→    /** @type {import('./types.ts').QueueOptions} Options the queue was created with. */
    53→    this.options = options;
    54→  }
    55→}
    56→
    57→// =============================================================================
    58→// Memory Queue Manager (Lightweight, poll-based)
    59→// =============================================================================
    60→
    61→/**
    62→ * In-memory queue manager that creates and manages MemoryQueueWithStorage instances.
    63→ *
    64→ * This manager maintains a registry of queues and provides CRUD operations
    65→ * for queue lifecycle management. It uses poll-based visibility timeout
    66→ * handling via the processAllExpired() method.
    67→ *
    68→ * @implements {import('./types.ts').QueueManager}
    69→ *
    70→ * @example
    71→ * import { MemoryQueueManager } from 'links-queue';
    72→ *
    73→ * const manager = new MemoryQueueManager();
    74→ *
    75→ * // Create a queue
    76→ * const queue = await manager.createQueue('my-queue', { maxSize: 1000 });
    77→ *
    78→ * // Use the queue
    79→ * console.log(`Queue depth: ${queue.getDepth()}`);
    80→ *
    81→ * // List all queues
    82→ * const queues = await manager.listQueues();
    83→ * console.log(`Total queues: ${queues.length}`);
    84→ */
    85→export class MemoryQueueManager {
    86→  /**
    87→   * Creates a new, empty queue manager.
    88→   *
    89→   * @param {Object} [config] - Optional configuration (accepted for API compatibility)
    90→   * @param {Object} [config.store] - Optional store (ignored, for API compatibility with LinksQueueManager)
    91→   *
    92→   * @example
    93→   * const manager = new MemoryQueueManager();
    94→   * // Or with config for API compatibility:
    95→   * const manager = new MemoryQueueManager({ store: someStore });
    96→   */
    97→  constructor(config = {}) {
    98→    // Note: store is accepted for API compatibility but not used
    99→    // MemoryQueueManager creates its own internal storage
   100→    void config;
   101→
   102→    /**
   103→     * Registry of managed queues.
   104→     * @type {Map<string, QueueEntry>}
   105→     * @private
   106→     */
   107→    this._queues = new Map();
   108→
   109→    /**
   110→     * Counter for dead letter items moved via automatic callback.
   111→     * Reset when processDeadLetters is called.
   112→     * @type {number}
   113→     * @private
   114→     */
   115→    this._autoDeadLetterCount = 0;
   116→  }
   117→
   118→  /**
   119→   * Returns the number of managed queues.
   120→   *
   121→   * @returns {number}
   122→   */
   123→  queueCount() {
   124→    return this._queues.size;
   125→  }
   126→
   127→  /**
   128→   * Gets the total number of queues (alias for queueCount for API compatibility).
   129→   *
   130→   * @returns {number} Number of queues
   131→   */
   132→  getQueueCount() {
   133→    return this._queues.size;
   134→  }
   135→
   136→  /**
   137→   * Checks if a queue with the given name exists.
   138→   *
   139→   * @param {string} name - The queue name to check
   140→   * @returns {boolean}
   141→   */
   142→  hasQueue(name) {
   143→    return this._queues.has(name);
   144→  }
   145→
   146→  /**
   147→   * Creates a new named queue with the specified options.
   148→   *
   149→   * If a queue with the same name already exists, an error is thrown.
   150→   *
   151→   * @param {string} name - Unique name for the queue
   152→   * @param {import('./types.ts').QueueOptions} [options={}] - Optional queue configuration
   153→   * @returns {Promise<MemoryQueueWithStorage>} Promise resolving to the created Queue
   154→   * @throws {QueueError} If a queue with this name already exists
   155→   *
   156→   * @example
   157→   * const queue = await manager.createQueue('my-queue', {
   158→   *   maxSize: 1000,
   159→   *   visibilityTimeout: 60
   160→   * });
   161→   */
   162→  async createQueue(name, options = {}) {
   163→    // Check if queue already exists
   164→    if (this._queues.has(name)) {
   165→      throw new QueueError(
   166→        'QUEUE_ALREADY_EXISTS',
   167→        `Queue '${name}' already exists`
   168→      );
   169→    }
   170→
   171→    // Create dead letter callback if DLQ is configured
   172→    const callbacks = {};
   173→    if (options.deadLetterQueue) {
   174→      callbacks.onDeadLetter = async (link) => {
   175→        const dlq = await this.getQueue(options.deadLetterQueue);
   176→        if (dlq) {
   177→          await dlq.enqueue(link);
   178→          this._autoDeadLetterCount++;
   179→        }
   180→        // If DLQ doesn't exist, item is dropped
   181→      };
   182→    }
   183→
   184→    // Create the queue
   185→    const queue = new MemoryQueueWithStorage(name, options, callbacks);
   186→
   187→    // Store the entry
   188→    const entry = new QueueEntry(queue, { ...options });
   189→    this._queues.set(name, entry);
   190→
   191→    return queue;
   192→  }
   193→
   194→  /**
   195→   * Deletes a queue and all its contents.
   196→   *
   197→   * Any in-flight items are lost. This operation is irreversible.
   198→   *
   199→   * @param {string} name - Name of the queue to delete
   200→   * @returns {Promise<boolean>} Promise resolving to true if queue was deleted, false if not found
   201→   *
   202→   * @example
   203→   * const deleted = await manager.deleteQueue('old-queue');
   204→   * if (deleted) {
   205→   *   console.log('Queue deleted');
   206→   * }
   207→   */
   208→  async deleteQueue(name) {
   209→    return this._queues.delete(name);
   210→  }
   211→
   212→  /**
   213→   * Retrieves an existing queue by name.
   214→   *
   215→   * @param {string} name - Name of the queue to retrieve
   216→   * @returns {Promise<MemoryQueueWithStorage | null>} Promise resolving to the Queue, or null if not found
   217→   *
   218→   * @example
   219→   * const queue = await manager.getQueue('tasks');
   220→   * if (queue) {
   221→   *   const depth = queue.getDepth();
   222→   *   console.log(`Queue has ${depth} items`);
   223→   * }
   224→   */
   225→  async getQueue(name) {
   226→    const entry = this._queues.get(name);
   227→    return entry ? entry.queue : null;
   228→  }
   229→
   230→  /**
   231→   * Lists all queues managed by this manager.
   232→   *
   233→   * @returns {Promise<import('./types.ts').QueueInfo[]>} Promise resolving to array of QueueInfo for all queues
   234→   *
   235→   * @example
   236→   * const queues = await manager.listQueues();
   237→   * for (const info of queues) {
   238→   *   console.log(`${info.name}: ${info.depth} items`);
   239→   * }
   240→   */
   241→  async listQueues() {
   242→    const infos = [];
   243→
   244→    for (const [name, entry] of this._queues) {
   245→      const stats = entry.queue.getStats();
   246→      infos.push({
   247→        name,
   248→        depth: stats.depth,
   249→        createdAt: entry.queue.createdAt,
   250→        options: { ...entry.options },
   251→      });
   252→    }
   253→
   254→    return infos;
   255→  }
   256→
   257→  /**
   258→   * Processes expired messages in all queues.
   259→   *
   260→   * This method should be called periodically to handle visibility timeouts.
   261→   * Returns a map of queue names to the number of messages requeued.
   262→   *
   263→   * @returns {Map<string, number>}
   264→   */
   265→  processAllExpired() {
   266→    const results = new Map();
   267→
   268→    for (const [name, entry] of this._queues) {
   269→      const count = entry.queue.processExpired();
   270→      if (count > 0) {
   271→        results.set(name, count);
   272→      }
   273→    }
   274→
   275→    return results;
   276→  }
   277→
   278→  /**
   279→   * Clears all queues and removes them from the manager.
   280→   *
   281→   * @returns {Promise<void>}
   282→   */
   283→  async clearAll() {
   284→    for (const entry of this._queues.values()) {
   285→      await entry.queue.clear();
   286→    }
   287→    this._queues.clear();
   288→  }
   289→
   290→  /**
   291→   * Moves dead letter items from source queues to their configured DLQs.
   292→   *
   293→   * Returns the number of items moved (including items that were
   294→   * automatically moved via the onDeadLetter callback since the last call).
   295→   *
   296→   * @returns {Promise<number>}
   297→   */
   298→  async processDeadLetters() {
   299→    // First, collect all dead letter items that are pending manual processing
   300→    const deadLetters = [];
   301→
   302→    for (const entry of this._queues.values()) {
   303→      const dlqName = entry.queue.getDeadLetterQueueName();
   304→      if (dlqName) {
   305→        const items = entry.queue.drainDeadLetters();
   306→        if (items.length > 0) {
   307→          deadLetters.push({ dlqName, items });
   308→        }
   309→      }
   310→    }
   311→
   312→    let totalMoved = 0;
   313→
   314→    // Now enqueue to DLQs (manual processing)
   315→    for (const { dlqName, items } of deadLetters) {
   316→      const dlq = await this.getQueue(dlqName);
   317→      if (dlq) {
   318→        for (const item of items) {
   319→          try {
   320→            await dlq.enqueue(item);
   321→            totalMoved++;
   322→          } catch {
   323→            // Ignore failures (e.g., DLQ full)
   324→          }
   325→        }
   326→      }
   327→    }
   328→
   329→    // Include items that were automatically moved via callback
   330→    totalMoved += this._autoDeadLetterCount;
   331→    this._autoDeadLetterCount = 0;
   332→
   333→    return totalMoved;
   334→  }
   335→}
   336→
   337→// =============================================================================
   338→// Links Queue Manager (Full-featured, timer-based)
   339→// =============================================================================
   340→
   341→/**
   342→ * LinksQueueManager - Manages the lifecycle of named LinksQueue instances.
   343→ *
   344→ * This manager uses a LinkStore backend for all queues and provides
   345→ * automatic timer-based visibility timeout handling and dead letter queue
   346→ * routing.
   347→ *
   348→ * @implements {import('./types.ts').QueueManager}
   349→ *
   350→ * @example
   351→ * import { LinksQueueManager, MemoryLinkStore } from 'links-queue';
   352→ *
   353→ * const store = new MemoryLinkStore();
   354→ * const manager = new LinksQueueManager({ store });
