/**
 * Queue manager implementations for links-queue.
 *
 * This module provides two queue manager implementations:
 *
 * 1. MemoryQueueManager - Lightweight manager for MemoryQueueWithStorage
 *    - No external dependencies
 *    - Uses poll-based visibility timeout handling
 *    - Good for simple use cases and testing
 *
 * 2. LinksQueueManager - Full-featured manager for LinksQueue
 *    - Requires a LinkStore backend for persistence
 *    - Uses timer-based visibility timeout handling
 *    - Supports automatic dead letter queue routing
 *    - Good for production use cases
 *
 * @module queue/manager
 *
 * @see ARCHITECTURE.md - Queue Manager component
 * @see REQUIREMENTS.md - REQ-API-010 through REQ-API-013
 */

/*
 * Note: The require-await warnings are intentional.
 * This implementation uses async methods for API consistency with other backends
 * (e.g., file-based or network-based managers) even though the in-memory operations
 * are synchronous. This allows for seamless backend swapping.
 */
/* eslint-disable require-await */

import { QueueError } from './types.js';
import { LinksQueue } from './queue.js';
import { MemoryQueueWithStorage } from './memory-queue.js';

// =============================================================================
// Queue Entry (Internal - for MemoryQueueManager)
// =============================================================================

/**
 * Internal entry for a managed queue.
 * @private
 */
class QueueEntry {
  /**
   * @param {MemoryQueueWithStorage} queue - The queue instance
   * @param {import('./types.ts').QueueOptions} options - Options the queue was created with
   */
  constructor(queue, options) {
    /** @type {MemoryQueueWithStorage} The queue instance. */
    this.queue = queue;

    /** @type {import('./types.ts').QueueOptions} Options the queue was created with. */
    this.options = options;
  }
}

// =============================================================================
// Memory Queue Manager (Lightweight, poll-based)
// =============================================================================

/**
 * In-memory queue manager that creates and manages MemoryQueueWithStorage instances.
 *
 * This manager maintains a registry of queues and provides CRUD operations
 * for queue lifecycle management. It uses poll-based visibility timeout
 * handling via the processAllExpired() method.
 *
 * @implements {import('./types.ts').QueueManager}
 *
 * @example
 * import { MemoryQueueManager } from 'links-queue';
 *
 * const manager = new MemoryQueueManager();
 *
 * // Create a queue
 * const queue = await manager.createQueue('my-queue', { maxSize: 1000 });
 *
 * // Use the queue
 * console.log(`Queue depth: ${queue.getDepth()}`);
 *
 * // List all queues
 * const queues = await manager.listQueues();
 * console.log(`Total queues: ${queues.length}`);
 */
export class MemoryQueueManager {
  /**
   * Creates a new, empty queue manager.
   *
   * @param {Object} [config] - Optional configuration (accepted for API compatibility)
   * @param {Object} [config.store] - Optional store (ignored, for API compatibility with LinksQueueManager)
   *
   * @example
   * const manager = new MemoryQueueManager();
   * // Or with config for API compatibility:
   * const manager = new MemoryQueueManager({ store: someStore });
   */
  constructor(config = {}) {
    // Note: store is accepted for API compatibility but not used
    // MemoryQueueManager creates its own internal storage
    void config;

    /**
     * Registry of managed queues.
     * @type {Map<string, QueueEntry>}
     * @private
     */
    this._queues = new Map();

    /**
     * Counter for dead letter items moved via automatic callback.
     * Reset when processDeadLetters is called.
     * @type {number}
     * @private
     */
    this._autoDeadLetterCount = 0;
  }

  /**
   * Returns the number of managed queues.
   *
   * @returns {number}
   */
  queueCount() {
    return this._queues.size;
  }

  /**
   * Gets the total number of queues (alias for queueCount for API compatibility).
   *
   * @returns {number} Number of queues
   */
  getQueueCount() {
    return this._queues.size;
  }

  /**
   * Checks if a queue with the given name exists.
   *
   * @param {string} name - The queue name to check
   * @returns {boolean}
   */
  hasQueue(name) {
    return this._queues.has(name);
  }

  /**
   * Creates a new named queue with the specified options.
   *
   * If a queue with the same name already exists, an error is thrown.
   *
   * @param {string} name - Unique name for the queue
   * @param {import('./types.ts').QueueOptions} [options={}] - Optional queue configuration
   * @returns {Promise<MemoryQueueWithStorage>} Promise resolving to the created Queue
   * @throws {QueueError} If a queue with this name already exists
   *
   * @example
   * const queue = await manager.createQueue('my-queue', {
   *   maxSize: 1000,
   *   visibilityTimeout: 60
   * });
   */
  async createQueue(name, options = {}) {
    // Check if queue already exists
    if (this._queues.has(name)) {
      throw new QueueError(
        'QUEUE_ALREADY_EXISTS',
        `Queue '${name}' already exists`
      );
    }

    // Create dead letter callback if DLQ is configured
    const callbacks = {};
    if (options.deadLetterQueue) {
      callbacks.onDeadLetter = async (link) => {
        const dlq = await this.getQueue(options.deadLetterQueue);
        if (dlq) {
          await dlq.enqueue(link);
          this._autoDeadLetterCount++;
        }
        // If DLQ doesn't exist, item is dropped
      };
    }

    // Create the queue
    const queue = new MemoryQueueWithStorage(name, options, callbacks);

    // Store the entry
    const entry = new QueueEntry(queue, { ...options });
    this._queues.set(name, entry);

    return queue;
  }

  /**
   * Deletes a queue and all its contents.
   *
   * Any in-flight items are lost. This operation is irreversible.
   *
   * @param {string} name - Name of the queue to delete
   * @returns {Promise<boolean>} Promise resolving to true if queue was deleted, false if not found
   *
   * @example
   * const deleted = await manager.deleteQueue('old-queue');
   * if (deleted) {
   *   console.log('Queue deleted');
   * }
   */
  async deleteQueue(name) {
    return this._queues.delete(name);
  }

  /**
   * Retrieves an existing queue by name.
   *
   * @param {string} name - Name of the queue to retrieve
   * @returns {Promise<MemoryQueueWithStorage | null>} Promise resolving to the Queue, or null if not found
   *
   * @example
   * const queue = await manager.getQueue('tasks');
   * if (queue) {
   *   const depth = queue.getDepth();
   *   console.log(`Queue has ${depth} items`);
   * }
   */
  async getQueue(name) {
    const entry = this._queues.get(name);
    return entry ? entry.queue : null;
  }

  /**
   * Lists all queues managed by this manager.
   *
   * @returns {Promise<import('./types.ts').QueueInfo[]>} Promise resolving to array of QueueInfo for all queues
   *
   * @example
   * const queues = await manager.listQueues();
   * for (const info of queues) {
   *   console.log(`${info.name}: ${info.depth} items`);
   * }
   */
  async listQueues() {
    const infos = [];

    for (const [name, entry] of this._queues) {
      const stats = entry.queue.getStats();
      infos.push({
        name,
        depth: stats.depth,
        createdAt: entry.queue.createdAt,
        options: { ...entry.options },
      });
    }

    return infos;
  }

  /**
   * Processes expired messages in all queues.
   *
   * This method should be called periodically to handle visibility timeouts.
   * Returns a map of queue names to the number of messages requeued.
   *
   * @returns {Map<string, number>}
   */
  processAllExpired() {
    const results = new Map();

    for (const [name, entry] of this._queues) {
      const count = entry.queue.processExpired();
      if (count > 0) {
        results.set(name, count);
      }
    }

    return results;
  }

  /**
   * Clears all queues and removes them from the manager.
   *
   * @returns {Promise<void>}
   */
  async clearAll() {
    for (const entry of this._queues.values()) {
      await entry.queue.clear();
    }
    this._queues.clear();
  }

  /**
   * Moves dead letter items from source queues to their configured DLQs.
   *
   * Returns the number of items moved (including items that were
   * automatically moved via the onDeadLetter callback since the last call).
   *
   * @returns {Promise<number>}
   */
  async processDeadLetters() {
    // First, collect all dead letter items that are pending manual processing
    const deadLetters = [];

    for (const entry of this._queues.values()) {
      const dlqName = entry.queue.getDeadLetterQueueName();
      if (dlqName) {
        const items = entry.queue.drainDeadLetters();
        if (items.length > 0) {
          deadLetters.push({ dlqName, items });
        }
      }
    }

    let totalMoved = 0;

    // Now enqueue to DLQs (manual processing)
    for (const { dlqName, items } of deadLetters) {
      const dlq = await this.getQueue(dlqName);
      if (dlq) {
        for (const item of items) {
          try {
            await dlq.enqueue(item);
            totalMoved++;
          } catch {
            // Ignore failures (e.g., DLQ full)
          }
        }
      }
    }

    // Include items that were automatically moved via callback
    totalMoved += this._autoDeadLetterCount;
    this._autoDeadLetterCount = 0;

    return totalMoved;
  }
}

// =============================================================================
// Links Queue Manager (Full-featured, timer-based)
// =============================================================================

/**
 * LinksQueueManager - Manages the lifecycle of named LinksQueue instances.
 *
 * This manager uses a LinkStore backend for all queues and provides
 * automatic timer-based visibility timeout handling and dead letter queue
 * routing.
 *
 * @implements {import('./types.ts').QueueManager}
 *
 * @example
 * import { LinksQueueManager, MemoryLinkStore } from 'links-queue';
 *
 * const store = new MemoryLinkStore();
 * const manager = new LinksQueueManager({ store });
 *
 * // Create queues
 * const tasksQueue = await manager.createQueue('tasks', {
 *   retryLimit: 3,
 *   deadLetterQueue: 'tasks-dlq'
 * });
 * const dlqQueue = await manager.createQueue('tasks-dlq');
 *
 * // List all queues
 * const queues = await manager.listQueues();
 * console.log(queues); // [{ name: 'tasks', depth: 0, ... }, ...]
 */
export class LinksQueueManager {
  /**
   * Creates a new LinksQueueManager.
   *
   * @param {Object} config - Manager configuration
   * @param {import('../backends/memory.js').MemoryLinkStore} config.store - LinkStore backend to use for all queues
   */
  constructor(config) {
    const { store } = config;

    /**
     * The underlying LinkStore.
     * @type {import('../backends/memory.js').MemoryLinkStore}
     * @private
     */
    this._store = store;

    /**
     * Registry of created queues.
     * @type {Map<string, LinksQueue>}
     * @private
     */
    this._queues = new Map();
  }

  /**
   * Creates a new named queue with the specified options.
   *
   * If a dead letter queue is specified in options, items that exceed the
   * retry limit will be automatically moved to that queue (if it exists).
   *
   * @param {string} name - Unique name for the queue
   * @param {import('./types.ts').QueueOptions} [options] - Queue configuration
   * @returns {Promise<import('./types.ts').Queue>} The created queue
   * @throws {QueueError} If a queue with this name already exists (QUEUE_ALREADY_EXISTS)
   */
  async createQueue(name, options = {}) {
    if (this._queues.has(name)) {
      throw new QueueError(
        'QUEUE_ALREADY_EXISTS',
        `Queue '${name}' already exists`
      );
    }

    // Create the dead letter handler if DLQ is specified
    const onDeadLetter = options.deadLetterQueue
      ? async (link) => {
          const dlq = this._queues.get(options.deadLetterQueue);
          if (dlq) {
            await dlq.enqueue(link);
          }
          // If DLQ doesn't exist, item is dropped (logged in production)
        }
      : undefined;

    const queue = new LinksQueue({
      name,
      store: this._store,
      options,
      onDeadLetter,
    });

    this._queues.set(name, queue);
    return queue;
  }

  /**
   * Deletes a queue and all its contents.
   *
   * Any in-flight items are lost. This operation is irreversible.
   *
   * @param {string} name - Name of the queue to delete
   * @returns {Promise<boolean>} True if queue was deleted, false if not found
   */
  async deleteQueue(name) {
    const queue = this._queues.get(name);
    if (!queue) {
      return false;
    }

    // Clear the queue to cancel any pending timeouts
    await queue.clear();

    this._queues.delete(name);
    return true;
  }

  /**
   * Retrieves an existing queue by name.
   *
   * @param {string} name - Name of the queue to retrieve
   * @returns {Promise<import('./types.ts').Queue | null>} The queue, or null if not found
   */
  async getQueue(name) {
    return this._queues.get(name) ?? null;
  }

  /**
   * Lists all queues managed by this manager.
   *
   * @returns {Promise<import('./types.ts').QueueInfo[]>} Array of QueueInfo for all queues
   */
  async listQueues() {
    const result = [];

    for (const [name, queue] of this._queues.entries()) {
      result.push({
        name,
        depth: queue.getDepth(),
        createdAt: queue.createdAt,
        options: queue.options,
      });
    }

    return result;
  }

  /**
   * Checks if a queue exists.
   *
   * @param {string} name - Name of the queue to check
   * @returns {boolean} True if queue exists
   */
  hasQueue(name) {
    return this._queues.has(name);
  }

  /**
   * Gets the total number of queues.
   *
   * @returns {number} Number of queues
   */
  getQueueCount() {
    return this._queues.size;
  }

  /**
   * Clears all queues and removes them from the manager.
   *
   * @returns {Promise<void>}
   */
  async clearAll() {
    for (const queue of this._queues.values()) {
      await queue.clear();
    }
    this._queues.clear();
  }
}

/**
 * Core Link and LinkStore type definitions for links-queue.
 *
 * This module provides the foundational interfaces for the Link data model
 * and LinkStore operations. These interfaces establish the API contract that
 * implementations must follow.
 *
 * @module types
 *
 * Design goals:
 * - Compatible with links-notation (supports nested/recursive structures)
 * - Compatible with doublets-rs patterns (source/target model)
 * - Extensible for universal links with any number of references
 *
 * @see https://github.com/link-foundation/links-notation
 * @see https://github.com/linksplatform/doublets-rs
 */

// =============================================================================
// ID Types
// =============================================================================

/**
 * A link identifier. Can be a number, bigint, or string.
 *
 * @example
 * const numericId: LinkId = 42;
 * const bigId: LinkId = 9007199254740993n;
 * const stringId: LinkId = "custom-uuid-here";
 */
export type LinkId = number | bigint | string;

// =============================================================================
// Link Reference Types
// =============================================================================

/**
 * A reference to a link, which can be:
 * - A link ID (direct reference by identifier)
 * - A nested Link object (inline definition)
 *
 * This allows for flexible link compositions and nested structures,
 * supporting arbitrary levels of recursion as required by links-notation.
 *
 * @example
 * // Direct reference by ID
 * const ref1: LinkRef = 42;
 *
 * // Nested link reference
 * const ref2: LinkRef = { id: 1, source: 2, target: 3 };
 *
 * // Deeply nested
 * const ref3: LinkRef = {
 *   id: 1,
 *   source: { id: 2, source: 3, target: 4 },
 *   target: 5
 * };
 */
export type LinkRef = LinkId | Link;

// =============================================================================
// Link Interface
// =============================================================================

/**
 * Represents a link (associative data structure) connecting source to target.
 *
 * A Link is the fundamental unit of data in links-queue. It represents
 * a directed relationship from a source to a target, identified by a unique ID.
 *
 * For compatibility with links-notation's universal link model, additional
 * values can be provided beyond the basic source/target pair.
 *
 * @property id - Unique identifier for this link
 * @property source - Reference to the source (can be another Link or LinkId)
 * @property target - Reference to the target (can be another Link or LinkId)
 * @property values - Optional additional values for universal links (extensibility)
 *
 * @example
 * // Simple doublet-style link
 * const link: Link = {
 *   id: 1,
 *   source: 2,
 *   target: 3
 * };
 *
 * @example
 * // Nested link structure
 * const nestedLink: Link = {
 *   id: 1,
 *   source: { id: 2, source: 0, target: 0 },
 *   target: { id: 3, source: 4, target: 5 }
 * };
 *
 * @example
 * // Universal link with additional values
 * const universalLink: Link = {
 *   id: 1,
 *   source: 2,
 *   target: 3,
 *   values: [4, 5, { id: 6, source: 7, target: 8 }]
 * };
 */
export interface Link {
  /**
   * Unique identifier for this link.
   */
  readonly id: LinkId;

  /**
   * Reference to the source of this link.
   * Can be a LinkId for direct reference or a nested Link for inline definition.
   */
  readonly source: LinkRef;

  /**
   * Reference to the target of this link.
   * Can be a LinkId for direct reference or a nested Link for inline definition.
   */
  readonly target: LinkRef;

  /**
   * Optional additional values for universal links.
   * Supports arbitrary number of references beyond source/target.
   * Compatible with links-notation's values array model.
   */
  readonly values?: readonly LinkRef[];
}

// =============================================================================
// Pattern Matching Types
// =============================================================================

/**
 * Special value indicating "any" match in pattern queries.
 * When used in a LinkPattern, matches any value in that position.
 */
export const Any = Symbol('Any');
export type AnyType = typeof Any;

/**
 * Pattern for matching links in queries.
 *
 * Uses `Any` symbol as a wildcard to match any value in that position.
 * Each field can be:
 * - A specific LinkRef value (exact match)
 * - The `Any` symbol (matches anything)
 * - undefined (not included in match criteria)
 *
 * @example
 * // Match all links with source = 5
 * const pattern: LinkPattern = { source: 5 };
 *
 * // Match all links with any source and target = 10
 * const pattern2: LinkPattern = { source: Any, target: 10 };
 *
 * // Match all links (equivalent to no filter)
 * const pattern3: LinkPattern = { source: Any, target: Any };
 */
export interface LinkPattern {
  /**
   * Match criteria for link ID.
   */
  readonly id?: LinkId | AnyType;

  /**
   * Match criteria for link source.
   */
  readonly source?: LinkRef | AnyType;

  /**
   * Match criteria for link target.
   */
  readonly target?: LinkRef | AnyType;
}

// =============================================================================
// LinkStore Interface
// =============================================================================

/**
 * Interface for link storage operations.
 *
 * Provides CRUD operations for managing links, plus query capabilities
 * with pattern matching support. This is the main interface that
 * implementations must satisfy.
 *
 * The design follows the doublets-rs trait pattern while maintaining
 * JavaScript/TypeScript idioms.
 *
 * @example
 * class InMemoryLinkStore implements LinkStore {
 *   // ... implementation
 * }
 *
 * const store: LinkStore = new InMemoryLinkStore();
 * const link = await store.create(1, 2);
 * console.log(link.id); // auto-generated ID
 */
export interface LinkStore {
  // ---------------------------------------------------------------------------
  // Create Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new link from source to target.
   *
   * The implementation should auto-generate a unique ID for the link.
   *
   * @param source - The source reference for the new link
   * @param target - The target reference for the new link
   * @returns The newly created Link with its assigned ID
   *
   * @example
   * const link = await store.create(1, 2);
   * console.log(link); // { id: 1, source: 1, target: 2 }
   */
  create(source: LinkRef, target: LinkRef): Promise<Link>;

  /**
   * Creates a new link with additional values (universal link).
   *
   * @param source - The source reference for the new link
   * @param target - The target reference for the new link
   * @param values - Additional value references
   * @returns The newly created Link
   */
  createWithValues(
    source: LinkRef,
    target: LinkRef,
    values: readonly LinkRef[]
  ): Promise<Link>;

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Retrieves a link by its ID.
   *
   * @param id - The ID of the link to retrieve
   * @returns The Link if found, null otherwise
   *
   * @example
   * const link = await store.get(42);
   * if (link) {
   *   console.log(`Found: ${link.source} -> ${link.target}`);
   * }
   */
  get(id: LinkId): Promise<Link | null>;

  /**
   * Checks if a link with the given ID exists.
   *
   * @param id - The ID to check
   * @returns True if the link exists, false otherwise
   *
   * @example
   * if (await store.exists(42)) {
   *   console.log('Link 42 exists');
   * }
   */
  exists(id: LinkId): Promise<boolean>;

  /**
   * Finds links matching the given pattern.
   *
   * Supports wildcards via the `Any` symbol for flexible querying.
   *
   * @param pattern - The pattern to match against
   * @returns Array of matching links
   *
   * @example
   * // Find all links with source = 5
   * const links = await store.find({ source: 5 });
   *
   * // Find all links with any source, target = 10
   * const links2 = await store.find({ source: Any, target: 10 });
   */
  find(pattern: LinkPattern): Promise<Link[]>;

  /**
   * Counts links matching the given pattern.
   *
   * If no pattern is provided, counts all links.
   *
   * @param pattern - Optional pattern to match against
   * @returns Count of matching links
   *
   * @example
   * const total = await store.count();
   * const withSource5 = await store.count({ source: 5 });
   */
  count(pattern?: LinkPattern): Promise<number>;

  // ---------------------------------------------------------------------------
  // Update Operations
  // ---------------------------------------------------------------------------

  /**
   * Updates an existing link's source and/or target.
   *
   * @param id - The ID of the link to update
   * @param source - New source reference
   * @param target - New target reference
   * @returns The updated Link
   * @throws If the link with given ID does not exist
   *
   * @example
   * const updated = await store.update(1, 10, 20);
   * console.log(updated); // { id: 1, source: 10, target: 20 }
   */
  update(id: LinkId, source: LinkRef, target: LinkRef): Promise<Link>;

  // ---------------------------------------------------------------------------
  // Delete Operations
  // ---------------------------------------------------------------------------

  /**
   * Deletes a link by its ID.
   *
   * @param id - The ID of the link to delete
   * @returns True if the link was deleted, false if it didn't exist
   *
   * @example
   * const deleted = await store.delete(42);
   * if (deleted) {
   *   console.log('Link 42 was deleted');
   * }
   */
  delete(id: LinkId): Promise<boolean>;

  /**
   * Deletes all links matching the given pattern.
   *
   * @param pattern - The pattern to match for deletion
   * @returns Count of deleted links
   *
   * @example
   * // Delete all links with source = 5
   * const count = await store.deleteMatching({ source: 5 });
   * console.log(`Deleted ${count} links`);
   */
  deleteMatching(pattern: LinkPattern): Promise<number>;

  // ---------------------------------------------------------------------------
  // Iteration Operations
  // ---------------------------------------------------------------------------

  /**
   * Iterates over all links matching the given pattern.
   *
   * Provides an async iterator for memory-efficient traversal of large datasets.
   *
   * @param pattern - Optional pattern to filter links
   * @returns AsyncIterable of matching links
   *
   * @example
   * for await (const link of store.iterate({ source: 5 })) {
   *   console.log(link);
   * }
   */
  iterate(pattern?: LinkPattern): AsyncIterable<Link>;
}

// =============================================================================
// Utility Types
// =============================================================================

/**
 * Extracts the ID type from a Link type.
 */
export type LinkIdOf<L extends Link> = L['id'];

/**
 * A mutable version of Link for internal use.
 */
export interface MutableLink {
  id: LinkId;
  source: LinkRef;
  target: LinkRef;
  values?: LinkRef[];
}

/**
 * Options for creating a new link.
 */
export interface CreateLinkOptions {
  /**
   * The source reference for the new link.
   */
  source: LinkRef;

  /**
   * The target reference for the new link.
   */
  target: LinkRef;

  /**
   * Optional additional values for universal links.
   */
  values?: LinkRef[];
}

/**
 * Result type for operations that might fail.
 */
export type LinkResult<T> =
  | { success: true; value: T }
  | { success: false; error: string };

// =============================================================================
// Re-exports for convenience
// =============================================================================

/**
 * @deprecated Use Link instead. ILink is provided for backward compatibility.
 */
export type ILink = Link;

