     1→/**
     2→ * Connection handling for Links Queue TCP server.
     3→ *
     4→ * This module provides the ServerConnection class for managing individual
     5→ * client connections, including message framing, parsing, and lifecycle.
     6→ *
     7→ * @module server/connection
     8→ */
     9→
    10→import { EventEmitter } from 'node:events';
    11→import { Message } from '../protocol/messages.js';
    12→
    13→// =============================================================================
    14→// Constants
    15→// =============================================================================
    16→
    17→/**
    18→ * Connection states.
    19→ * @readonly
    20→ * @enum {string}
    21→ */
    22→export const ConnectionState = Object.freeze({
    23→  /** Connection is being established */
    24→  CONNECTING: 'connecting',
    25→  /** Connection is active and ready */
    26→  CONNECTED: 'connected',
    27→  /** Connection is draining (graceful shutdown) */
    28→  DRAINING: 'draining',
    29→  /** Connection is closed */
    30→  CLOSED: 'closed',
    31→});
    32→
    33→/**
    34→ * Default connection options.
    35→ */
    36→const DEFAULT_OPTIONS = {
    37→  idleTimeout: 60000, // 60 seconds
    38→  maxMessageSize: 10 * 1024 * 1024, // 10MB
    39→  heartbeatInterval: 30000, // 30 seconds
    40→};
    41→
    42→/**
    43→ * Message delimiter for framing.
    44→ * Uses newline as delimiter for Links Notation messages.
    45→ */
    46→const MESSAGE_DELIMITER = '\n';
    47→
    48→// =============================================================================
    49→// ServerConnection Class
    50→// =============================================================================
    51→
    52→/**
    53→ * Represents a single client connection to the server.
    54→ *
    55→ * Handles message framing, parsing, and connection lifecycle.
    56→ * Emits events for incoming messages and connection state changes.
    57→ *
    58→ * @extends EventEmitter
    59→ *
    60→ * @fires ServerConnection#message - When a complete message is received
    61→ * @fires ServerConnection#error - When an error occurs
    62→ * @fires ServerConnection#close - When the connection is closed
    63→ * @fires ServerConnection#drain - When the write buffer is drained
    64→ *
    65→ * @example
    66→ * const connection = new ServerConnection(socket, {
    67→ *   idleTimeout: 60000,
    68→ *   maxMessageSize: 1024 * 1024
    69→ * });
    70→ *
    71→ * connection.on('message', async (message) => {
    72→ *   const response = await handleMessage(message);
    73→ *   connection.send(response);
    74→ * });
    75→ *
    76→ * connection.on('close', () => {
    77→ *   console.log('Client disconnected:', connection.id);
    78→ * });
    79→ */
    80→export class ServerConnection extends EventEmitter {
    81→  /**
    82→   * Counter for generating unique connection IDs.
    83→   * @type {number}
    84→   * @private
    85→   * @static
    86→   */
    87→  static #idCounter = 0;
    88→
    89→  /**
    90→   * Creates a new ServerConnection.
    91→   *
    92→   * @param {import('node:net').Socket} socket - The underlying TCP socket
    93→   * @param {Object} [options] - Connection options
    94→   * @param {number} [options.idleTimeout=60000] - Idle timeout in milliseconds
    95→   * @param {number} [options.maxMessageSize=10485760] - Maximum message size in bytes
    96→   * @param {number} [options.heartbeatInterval=30000] - Heartbeat interval in milliseconds
    97→   */
    98→  constructor(socket, options = {}) {
    99→    super();
   100→
   101→    /**
   102→     * Unique connection identifier.
   103→     * @type {string}
   104→     */
   105→    this.id = `conn-${++ServerConnection.#idCounter}-${Date.now().toString(36)}`;
   106→
   107→    /**
   108→     * The underlying TCP socket.
   109→     * @type {import('node:net').Socket}
   110→     * @private
   111→     */
   112→    this._socket = socket;
   113→
   114→    /**
   115→     * Connection options.
   116→     * @type {Object}
   117→     * @private
   118→     */
   119→    this._options = {
   120→      idleTimeout: options.idleTimeout ?? DEFAULT_OPTIONS.idleTimeout,
   121→      maxMessageSize: options.maxMessageSize ?? DEFAULT_OPTIONS.maxMessageSize,
   122→      heartbeatInterval:
   123→        options.heartbeatInterval ?? DEFAULT_OPTIONS.heartbeatInterval,
   124→    };
   125→
   126→    /**
   127→     * Current connection state.
   128→     * @type {string}
   129→     */
   130→    this.state = ConnectionState.CONNECTING;
   131→
   132→    /**
   133→     * Remote address of the client.
   134→     * @type {string}
   135→     */
   136→    this.remoteAddress = socket.remoteAddress || 'unknown';
   137→
   138→    /**
   139→     * Remote port of the client.
   140→     * @type {number}
   141→     */
   142→    this.remotePort = socket.remotePort || 0;
   143→
   144→    /**
   145→     * Timestamp when connection was established.
   146→     * @type {number}
   147→     */
   148→    this.connectedAt = Date.now();
   149→
   150→    /**
   151→     * Timestamp of last activity.
   152→     * @type {number}
   153→     */
   154→    this.lastActivity = Date.now();
   155→
   156→    /**
   157→     * Message buffer for incomplete messages.
   158→     * @type {string}
   159→     * @private
   160→     */
   161→    this._buffer = '';
   162→
   163→    /**
   164→     * Idle timeout timer.
   165→     * @type {NodeJS.Timeout|null}
   166→     * @private
   167→     */
   168→    this._idleTimer = null;
   169→
   170→    /**
   171→     * Heartbeat timer.
   172→     * @type {NodeJS.Timeout|null}
   173→     * @private
   174→     */
   175→    this._heartbeatTimer = null;
   176→
   177→    /**
   178→     * Number of messages received.
   179→     * @type {number}
   180→     */
   181→    this.messagesReceived = 0;
   182→
   183→    /**
   184→     * Number of messages sent.
   185→     * @type {number}
   186→     */
   187→    this.messagesSent = 0;
   188→
   189→    /**
   190→     * Number of bytes received.
   191→     * @type {number}
   192→     */
   193→    this.bytesReceived = 0;
